import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"en/Page/page-settings.md","filePath":"en/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"en/Page/page-settings.md"};function n(i,t,s,l,g,c){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings control site display, upload page defaults, background images, and admin panel appearance.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>Title shown in the browser tab.</td></tr><tr><td>Site icon</td><td>Small icon shown in the browser tab.</td></tr><tr><td>ImgBed name</td><td>Name shown on the frontend pages.</td></tr><tr><td>ImgBed logo</td><td>Logo image shown on the frontend pages.</td></tr><tr><td>Logo link</td><td>URL opened when clicking the logo or avatar.</td></tr><tr><td>Background switch interval</td><td>Rotation interval for multiple backgrounds, in milliseconds. <code>60000</code> means 60 seconds.</td></tr><tr><td>Background opacity</td><td>Background image opacity from <code>0</code> to <code>1</code>. Lower values are lighter.</td></tr><tr><td>Default URL prefix</td><td>Prefix used when generating image links. Empty means the current site domain is used.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>Announcement shown at the top of the upload page. HTML is supported.</td></tr><tr><td>Default upload channel</td><td>The upload channel selected by default on the upload page. You can also choose Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Default upload directory, such as <code>/user/</code>. Empty or <code>/</code> means root.</td></tr><tr><td>Default naming method</td><td>Default filename generation strategy after upload. See below.</td></tr><tr><td>Convert to WebP by default</td><td>Converts images to WebP before upload.</td></tr><tr><td>Enable compression by default</td><td>Compresses images locally in the browser before upload.</td></tr><tr><td>Default compression threshold</td><td>Automatically compress when an image exceeds this size, in MB.</td></tr><tr><td>Default target size</td><td>Target file size after compression, in MB.</td></tr><tr><td>Login page background</td><td>Background image for the user login page.</td></tr><tr><td>Upload page background</td><td>Background image for the upload page.</td></tr><tr><td>Footer portal link</td><td>URL opened by the footer portal button.</td></tr><tr><td>Hide footer</td><td>Hides the frontend footer when enabled.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>Background image for the admin login page.</td></tr><tr><td>Admin background</td><td>Background image for admin pages. Use one image URL or multiple URLs.</td></tr><tr><td>Image loading mode</td><td>Preview loading mode for the admin file list. Original loads original images. Smart loading prefers thumbnails for public images and originals for restricted images.</td></tr><tr><td>Thumbnail source</td><td>Service used to generate thumbnails: wsrv.nl, Cloudflare Image Resizing, or WordPress Photon. Cloudflare Image Resizing must be enabled in Cloudflare before selecting it.</td></tr><tr><td>Live2D widget</td><td>Shows a Live2D character in the admin panel.</td></tr><tr><td>Firework click effect</td><td>Shows a firework effect when clicking the page.</td></tr><tr><td>Star cursor trail</td><td>Shows a star trail when moving the mouse.</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background, and admin login background support these formats:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Uses Bing wallpaper rotation.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Rotates multiple images.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Uses a single background image.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Uses a random image API link. You can configure your own Random Image API in Other Settings, then paste the generated random image link here as a single-background entry.</td></tr></tbody></table><p>The admin background supports image URLs. Multiple URLs can be separated by English commas as prompted on the page. Empty means the default background is used.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, such as <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Time-random prefix and extension only, such as <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Keeps the original filename, such as <code>cat.png</code>. If duplicated, ImgBed adds <code>(1)</code>, <code>(2)</code>, and so on.</td></tr><tr><td>Short link</td><td>Uses an 8-character short ID and extension, such as <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=e(r,[["render",n]]);export{m as __pageData,u as default};
